package javaprj.day05;

public class 실습_2차원배열 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		String[][] pokemon= {
				{"이브이", "님피아", "블래키", "샤미드", "글레이시아"},
				{"피카츄", "파치리스", "빠모트", "데덴네", "에몽가"},
				{"한카리아스", "루카리오", "드래펄트", "망나뇽", "마기라스"},
				{"미라이돈", "레쿠쟈", "뮤츠", "루기아", "다크라이"}
		};
		
		System.out.println("<이브이즈>");
		System.out.println(pokemon[0][0]);
		System.out.println(pokemon[0][1]);
		System.out.println(pokemon[0][2]);
		System.out.println(pokemon[0][3]);
		System.out.println(pokemon[0][4]);
		
		System.out.println("\n<전기쥐>");
		System.out.println(pokemon[1][0]);
		System.out.println(pokemon[1][1]);
		System.out.println(pokemon[1][2]);
		System.out.println(pokemon[1][3]);
		System.out.println(pokemon[1][4]);
		
		System.out.println("\n<600족>");
		System.out.println(pokemon[2][0]);
		System.out.println(pokemon[2][1]);
		System.out.println(pokemon[2][2]);
		System.out.println(pokemon[2][3]);
		System.out.println(pokemon[2][4]);
		
		System.out.println("\n<전설>");
		System.out.println(pokemon[3][0]);
		System.out.println(pokemon[3][1]);
		System.out.println(pokemon[3][2]);
		System.out.println(pokemon[3][3]);
		System.out.println(pokemon[3][4]);

	}

}
